#include <stdio.h>

int factorial(int n) {
    if (n <= 1) {
        return 1;
    }
    return n * factorial(n - 1);
}

int main(void) {
    printf("Factorial: %d\n", factorial(5));
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct Nodo {
    int dato;
    struct Nodo *siguiente;
} Nodo;

Nodo *crear_nodo(int dato) {
    Nodo *nuevo = malloc(sizeof *nuevo);
    if (nuevo == NULL) return NULL;
    nuevo->dato = dato;
    nuevo->siguiente = NULL;
    return nuevo;
}

int main(void) {
    Nodo *primero = crear_nodo(10);
    Nodo *segundo = crear_nodo(20);
    if (primero == NULL || segundo == NULL) {
        free(primero);
        free(segundo);
        return 1;
    }
    primero->siguiente = segundo;
    printf("%d -> %d\n", primero->dato, primero->siguiente->dato);
    free(segundo);
    free(primero);
    return 0;
}

